/// Defines the visual properties of a ListTile.
///
/// Used to choose between a standard ListTile appearance ([list])
/// or one that is typically used in a [Drawer] ([drawer]).
enum StacListTileStyle {
  /// A typical list tile.
  /// This is the default style.
  list,

  /// A list tile that is typically used in a [Drawer].
  /// This style is often more compact.
  drawer,
}
